```ts
function createFakeDocument() {
  return {...}
}

let document: DOCUMENT;

beforeEach(async () => {
  await TestBed.configureTestingModule({
      providers: [
        {
          provide: DOCUMENT,
          useFactory: createFakeDocument
        },
        ...
