I suggest something like this instead. It removes the need for keeping track of the length of the previous data line, making the code easier to understand.

``` python
    def add_ti_txt(self, records, overwrite=False):
        """Add given TI-TXT records. Set `overwrite` to ``True`` to allow
        already added data to be overwritten.

        """

        address = None
        eol_found = False

        for record in StringIO(records):
            # Abort if data is found after end of line.
            if eol_found:
                raise Error("bad file terminator")

            if record[0] == 'q':
                # Check if the line is EOL.
                eol_found = True
            elif record[0] == '@':
                # Check if record is an address.
                try:
                    address = int(record[1:], 16)
                except ValueError:
                    raise Error("bad section address")
            else:
                # Try to decode data
                try:
                    data = bytearray(binascii.unhexlify(record.strip().replace(" ", "")))
                except (TypeError, binascii.Error):
                    raise Error("bad data: {}".format(record))

                if address is None:
                    raise Error("missing section address")

                size = len(data)

                if size > TI_TXT_BYTES_PER_LINE:
                    raise Error("line too long")
                
                segment = _Segment(address, address + size, data)
                self._segments.add(segment, overwrite)
                
                if size == TI_TXT_BYTES_PER_LINE:
                    address += size
                else:
                    address = None

        if not eol_found:
            raise Error("missing file terminator")
```

